def is_valid_blob_path(path: str) -> bool:
    """
    Validate blob path to prevent injection attacks
    """
    if not path or len(path) > 1024:
        return False
    
    # Security: Block dangerous patterns
    dangerous_patterns = [
        r'\.\.',  # Path traversal
        r'[<>"|?*]',  # Invalid characters
        r'^\/',  # Absolute paths
        r'^\\',  # Windows absolute paths
        r'[\x00-\x1f]',  # Control characters
    ]
    
    for pattern in dangerous_patterns:
        if re.search(pattern, path):
            return False
    
    return True


def normalize_blob_path(path: str) -> str:
    """
    Normalize blob path to prevent path traversal
    """
    # Replace backslashes with forward slashes
    normalized = path.replace('\\', '/')
    
    # Remove leading/trailing slashes
    normalized = normalized.strip('/')
    
    # Split path and remove empty parts and dots
    parts = [p for p in normalized.split('/') if p and p != '.' and p != '..']
    
    # Rejoin
    return '/'.join(parts)